using namespace std;

int main() {
   string s; cin>>s;
   string word = "ubercab";
   vector<int> freq_word(26,0);
   for(int i=0;i<7;i++){
       freq_word[word[i]-'a']++;
   }
   vector<int> s_freq(26,0);
   for(int i=0;i<s.size();i++){
       if(s[i] == ' ')continue;
       s_freq[s[i]-'a']++;
       if(freq_word[s[i]-'a']==0) {cout<<-1;return 0;}
   }
   int max_count = 1;
   for(int i=0;i<s.size();i++){
       int count =1;
       if(s_freq[s[i]-'a']){
           int temp = s_freq[s[i]-'a'];
           int f = freq_word[s[i]-'a'];
           count = temp/f+temp%f;
       }
    max_count = max(max_count,count);

   }
   cout<<max_count;

   return 0;
}

