private static int numOfUberStickers(String uberSticket, String s) {

	s = s.replaceAll(" ", "");

	HashMap<Character, Integer> uberMap = new HashMap<>();
	HashMap<Character, Integer> sMap = new HashMap<>();

	char[] uberSticketChs = uberSticket.toCharArray();
	char[] sChs = s.toCharArray();

	for (char ch : uberSticketChs)
		uberMap.put(ch, uberMap.getOrDefault(ch, 0) + 1);

	for (char ch : sChs)
		sMap.put(ch, sMap.getOrDefault(ch, 0) + 1);

	Set<Entry<Character, Integer>> sSet = sMap.entrySet();
	ArrayList<Entry<Character, Integer>> sEntries = new ArrayList<>(sSet);

	int result = 0;

	for (int i = 0; i < sEntries.size(); i++) {
		Entry<Character, Integer> entry = sEntries.get(i);
		char sKey = entry.getKey();
		int sNum = entry.getValue();

		// no char at stickers
		if (!uberMap.containsKey(sKey))
			return -1;

		if (uberMap.get(sKey) >= sNum)
			result = Math.max(result, 1);

		else { // (uberMap.get(sKey) < sNum
			int num = (int) Math.ceil((double)sNum / (double)uberMap.get(sKey));
			result = Math.max(result, num);
		}
	}

	return result;
}

