Explanation: create a dictionary with counts from ubercab sticker..... then create a dictionary with counts from input_str (If we find a char that is not in ubercab, we can immediately return). Then iterate for every char in input_str to calculate number of stickers needed for that char.

```
import math
def num_stickers(input_str, default_sticker='ubercab'):
    if not input_str:
        return 0
    default_sticker_chars={}
    for char in default_sticker:
        if char in default_sticker_chars.keys():
            default_sticker_chars[char]+=1.0
        else:
            default_sticker_chars[char]=1.0
    input_str_chars={}
    for char in input_str:
        if char==' ':
            continue
        if char not in default_sticker_chars.keys():
            return -1
        if char in input_str_chars.keys():
            input_str_chars[char]+=1.0
        else:
            input_str_chars[char]=1.0
    num_stickers=0
    for k,v in input_str_chars.items():
        num_stickers=max(num_stickers, math.ceil(v/default_sticker_chars[k]))
    return num_stickers
